/**
 * @name XSS: HTTP request parameters written to response output
 * @description User-controlled input from HTTP requests written to HTTP response without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-request-to-response
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources
import semmle.code.java.dataflow.DataFlow

module XssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // PrintWriter write/println
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // HttpServletResponse getOutputStream write
    exists(MethodCall mc |
      mc.getMethod().hasName("write") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "OutputStream") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module XssFlow = TaintTracking::Global<XssConfig>;
import XssFlow::PathGraph

from XssFlow::PathNode source, XssFlow::PathNode sink
where XssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS: user input from $@ flows to response output without encoding.", source.getNode(), "user input"

/**
 * @name XSS in RaftController - request body written to response
 * @description RaftController reads request body and writes to response output stream
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-raft-controller
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module RaftXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Request input stream / body reading in RaftController
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("com.alibaba.nacos.naming.controllers", "RaftController") and
      (
        mc.getMethod().hasName(["getInputStream", "getReader", "getParameter", "getBody"]) or
        // IoUtils.toString reading the request
        mc.getMethod().hasName("toString") and mc.getMethod().getDeclaringType().hasQualifiedName("com.alibaba.nacos.common.utils", "IoUtils")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("write") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "OutputStream") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module RaftXssFlow = TaintTracking::Global<RaftXssConfig>;
import RaftXssFlow::PathGraph

from RaftXssFlow::PathNode source, RaftXssFlow::PathNode sink
where RaftXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XSS: RaftController request body flows to response output at $@.", source.getNode(), "source"

/**
 * @name XSS in DistroFilter - proxied response body written to client
 * @description DistroFilter forwards request to backend and writes response body back to client without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-distro-filter
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module DistroXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HTTP response body from backend - proxied by DistroFilter from NacosRestTemplate
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("naming/src/main/java/com/alibaba/nacos/naming/web", "DistroFilter") or
      mc.getEnclosingCallable().getDeclaringType().getQualifiedName() = "com.alibaba.nacos.naming.web.DistroFilter"
    ) and
    source.asExpr().(MethodCall).getMethod().hasName(["getBody", "getData"])
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module DistroXssFlow = TaintTracking::Global<DistroXssConfig>;
import DistroXssFlow::PathGraph

from DistroXssFlow::PathNode source, DistroXssFlow::PathNode sink
where DistroXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XSS: DistroFilter proxied response written to client without encoding at $@.", source.getNode(), "source"

/**
 * @name XSS: User input in DistroFilter written to response via WebUtils
 * @description DistroFilter uses WebUtils.writeErrMsg to write response body data directly to client
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-distro-filter-precise
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module DistroFilterXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The body/data coming back from the proxied HTTP call in DistroFilter
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("com.alibaba.nacos.naming.web", "DistroFilter") and
      mc.getMethod().hasName(["getBody", "getData", "getMessage", "getMessage", "getErrorMsg"]) and
      source.asExpr() = mc
    )
    or
    // Request parameters in DistroFilter  
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("com.alibaba.nacos.naming.web", "DistroFilter") and
      mc.getMethod().hasName(["getParameter", "getHeader"]) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // WebUtils.writeErrMsg writes directly to response
    exists(MethodCall mc |
      mc.getMethod().hasName("writeErrMsg") and
      mc.getMethod().getDeclaringType().hasQualifiedName("com.alibaba.nacos.core.utils", "WebUtils") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Direct writer calls
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module DistroFilterXssFlow = TaintTracking::Global<DistroFilterXssConfig>;
import DistroFilterXssFlow::PathGraph

from DistroFilterXssFlow::PathNode source, DistroFilterXssFlow::PathNode sink
where DistroFilterXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XSS in DistroFilter: data at $@ flows to response output without encoding.", source.getNode(), "source"

/**
 * @name XSS in exception/error handlers - exception messages in response
 * @description Exception handlers that include user-controlled data in error responses
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-exception-handler
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ExceptionXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Response.sendError with user-controlled message
    exists(MethodCall mc |
      mc.getMethod().hasName("sendError") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletResponse") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Response addHeader with user-controlled value
    exists(MethodCall mc |
      mc.getMethod().hasName(["addHeader", "setHeader"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletResponse") and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module ExceptionXssFlow = TaintTracking::Global<ExceptionXssConfig>;
import ExceptionXssFlow::PathGraph

from ExceptionXssFlow::PathNode source, ExceptionXssFlow::PathNode sink
where ExceptionXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XSS via HTTP response header/error: user input at $@ flows to response header or sendError.", source.getNode(), "user input"
